class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        int n = nums.size();
        for (int i = 0; i < n - 1; ++i) {
            int sum = 0;
            for (int j = i; j < n; ++j) {
                sum += nums[j];
                if (sum % k == 0 && j - i + 1 >= 2) {
                    return true;
                }
            }
        }
        return false;
    }
};
